{"content":"use std::sync::RwLock;

use crate::api::SearchResult;

#[derive(Debug)]
struct Storage {
    ids: Vec<u64>,
    vectors: Vec<f32>,
    dim: usize,
}

pub struct VectorDB {
    storage: RwLock<Storage>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            storage: RwLock::new(Storage {
                ids: Vec::new(),
                vectors: Vec::new(),
                dim: 128,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut s = self.storage.write().unwrap();
        debug_assert_eq!(vector.len(), s.dim);
        s.ids.push(id);
        s.vectors.extend(vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut s = self.storage.write().unwrap();
        let n = vectors.len();
        let mut total_elements = 0usize;
        for (_, ref v) in &vectors {
            debug_assert_eq!(v.len(), s.dim);
            total_elements += v.len();
        }
        s.vectors.reserve(total_elements);
        s.ids.reserve(n);
        for (id, v) in vectors {
            s.ids.push(id);
            s.vectors.extend(v);
        }
        n
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        debug_assert_eq!(vector.len(), 128);
        let s = self.storage.read().unwrap();
        let num = s.ids.len();
        if num == 0 || top_k == 0 {
            return vec![];
        }
        let dim = s.dim;
        let mut candidates: Vec<(f64, u64)> = Vec::with_capacity(num);
        for i in 0..num {
            let offset = i * dim;
            let vec_slice = &s.vectors[offset..offset + dim];
            let dist = crate::distance::l2_distance(vector, vec_slice);
            candidates.push((dist, s.ids[i]));
        }
        let k = top_k.min(num as u32) as usize;
        candidates.partial_sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
        candidates.truncate(k);
        candidates
            .into_iter()
            .map(|(dist, id)| SearchResult { id, distance: dist })
            .collect()
    }
}","path":"src/db.rs"}

{"content":"pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());
    let mut sum_sq = 0.0f64;
    for i in 0..a.len() {
        let diff = a[i] as f64 - b[i] as f64;
        sum_sq += diff * diff;
    }
    sum_sq.sqrt()
}","path":"src/distance.rs"}

