{"content":"use std::sync::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;

use crate::api::SearchResult;

#[derive(Debug)]
struct Storage {
    ids: Vec<u64>,
    vectors: Vec<f32>,
    dim: usize,
}

pub struct VectorDB {
    storage: RwLock<Storage>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            storage: RwLock::new(Storage {
                ids: Vec::new(),
                vectors: Vec::new(),
                dim: 128,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut s = self.storage.write().unwrap();
        debug_assert_eq!(vector.len(), s.dim);
        s.ids.push(id);
        s.vectors.extend(vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut s = self.storage.write().unwrap();
        let n = vectors.len();
        let mut total_elements = 0usize;
        for (_, ref v) in &vectors {
            debug_assert_eq!(v.len(), s.dim);
            total_elements += v.len();
        }
        s.vectors.reserve(total_elements);
        s.ids.reserve(n);
        for (id, v) in vectors {
            s.ids.push(id);
            s.vectors.extend(v);
        }
        n
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let s = self.storage.read().unwrap();
        let num_vecs = s.ids.len();
        let dim = s.dim;
        let k = top_k.min(num_vecs as u32) as usize;
        if num_vecs == 0 || k == 0 {
            return vec![];
        }

        let chunk_size = (num_vecs + 3) / 4;

        let partial_topks: Vec<Vec<(f64, u64)>> = (0..4usize)
            .into_par_iter()
            .map(|tid| {
                let start = tid * chunk_size;
                let end = (start + chunk_size).min(num_vecs);
                let mut local_heap: BinaryHeap<(f64, u64)> = BinaryHeap::with_capacity(k);
                for i in start..end {
                    let offset = i * dim;
                    let vec_slice = &s.vectors[offset..offset + dim];
                    let dist = crate::distance::l2_distance(query, vec_slice);
                    let id = s.ids[i];
                    if local_heap.len() < k {
                        local_heap.push((dist, id));
                    } else if let Some(&top_dist) = local_heap.peek() {
                        if dist < top_dist.0 {
                            local_heap.pop();
                            local_heap.push((dist, id));
                        }
                    }
                }
                let mut res: Vec<(f64, u64)> = local_heap.into_iter().collect();
                res.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
                res
            })
            .collect();

        let mut candidates: Vec<(f64, u64)> = partial_topks.into_iter().flatten().collect();
        candidates.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
        if candidates.len() > k {
            candidates.truncate(k);
        }

        candidates
            .into_iter()
            .map(|(dist, id)| SearchResult { id, distance: dist })
            .collect()
    }
}","path":"src/db.rs"}

