{"content":"use std::sync::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;
use crate::api::SearchResult;

#[derive(Copy, Clone, Eq, PartialEq)]
struct DistId {
    dist: f64,
    id: u64,
}

impl Ord for DistId {
    fn cmp(&self, other: &Self) -> Ordering {
        match self.dist.total_cmp(&other.dist) {
            Ordering::Equal => self.id.cmp(&other.id),
            ord => ord,
        }
    }
}

impl PartialOrd for DistId {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        match self.dist.partial_cmp(&other.dist) {
            Some(Ordering::Equal) => self.id.partial_cmp(&other.id),
            other => other,
        }
    }
}

#[derive(Debug)]
struct Storage {
    ids: Vec<u64>,
    vectors: Vec<f32>,
    dim: usize,
}

pub struct VectorDB {
    storage: RwLock<Storage>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            storage: RwLock::new(Storage {
                ids: Vec::new(),
                vectors: Vec::new(),
                dim: 128,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut s = self.storage.write().unwrap();
        debug_assert_eq!(vector.len(), s.dim);
        s.ids.push(id);
        s.vectors.extend(vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut s = self.storage.write().unwrap();
        let n = vectors.len();
        let mut total_elements = 0usize;
        for (_, ref v) in &vectors {
            debug_assert_eq!(v.len(), s.dim);
            total_elements += v.len();
        }
        s.vectors.reserve(total_elements);
        s.ids.reserve(n);
        for (id, v) in vectors {
            s.ids.push(id);
            s.vectors.extend(v);
        }
        n
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        debug_assert_eq!(query.len(), 128);
        let s = self.storage.read().unwrap();
        let num_vecs = s.ids.len();
        let dim = s.dim;
        let k = top_k.min(num_vecs as u32) as usize;
        if num_vecs == 0 || k == 0 {
            return vec![];
        }

        let chunk_size = (num_vecs + 3) / 4;

        let partial_topks: Vec<Vec<(f64, u64)>> = (0..4)
            .into_par_iter()
            .map(|tid| {
                let start = tid * chunk_size;
                let end = (start + chunk_size).min(num_vecs);
                let mut local_heap: BinaryHeap<DistId> = BinaryHeap::with_capacity(k);
                for i in start..end {
                    let offset = i * dim;
                    let vec_slice = &s.vectors[offset..offset + dim];
                    let dist = crate::distance::l2_distance(query, vec_slice);
                    let id = s.ids[i];
                    if local_heap.len() < k as usize {
                        local_heap.push(DistId { dist, id });
                    } else if let Some(top) = local_heap.peek() {
                        if dist < top.dist {
                            local_heap.pop();
                            local_heap.push(DistId { dist, id });
                        }
                    }
                }
                let mut res: Vec<(f64, u64)> = local_heap.into_iter()
