pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());
    debug_assert_eq!(a.len(), 128);
    let mut sum_sq: f32 = 0.0;
    for i in 0..128 {
        let diff = a[i] - b[i];
        sum_sq += diff * diff;
    }
    f64::sqrt(sum_sq as f64)
}

